#!/bin/bash
# PolarSeg-input scovox for SemanticKITTI seqs 06-10 (predictions/ as semantic
# input), then score vs voxelized GT. Requires predictions/*.label already
# generated by run_polarseg_inference.sh. Sequential.
set -o pipefail
WS=/home/kalhan/Projects/scovox_ws
KE="${WS}/experiments/kitti"
OUT="${WS}/experiments/results/kitti_polarseg"
SEQS="06 07 08 09 10"

for s in ${SEQS}; do
  echo "======== PolarSeg seq ${s} ========"
  if [ ! -d "${WS}/data/semantickitti/dataset/sequences/${s}/predictions" ]; then
    echo "  MISSING predictions/ for seq ${s} — run run_polarseg_inference.sh first"; continue
  fi
  bash "${KE}/run_kitti.sh" "${s}" predictions "atlas_ps" \
       "${OUT}/${s}/scovox.npz" "${OUT}/${s}/run.log" 2>&1 \
       | grep -vE 'Waiting for TF|frames gated' | tail -8
done

echo "======== SCORING PolarSeg ========"
export PATH=$(echo "$PATH" | tr ':' '\n' | grep -v miniconda | tr '\n' ':' | sed 's/:$//')
python3 "${KE}/score_kitti.py" "${OUT}" --tag polarseg
echo "POLARSEG BATCH DONE"
